      const settled = await Promise.allSettled(
        ids.map(id => fetch(`/api/projects/${id}`).then(r => r.json()))
      );
      setProjects(settled.filter(r => r.status === "fulfilled").map(r => r.value));
    }
    load();
  }, [userId]);

  return (
    <ul>
      {projects.map(p => <li key={p.id}>{p.name}</li>)}
    </ul>
  );
}

